sql:
SELECT COUNT(DISTINCT computer_name) AS total_computers_with_security_events
FROM event_logs
WHERE event_type = 'security';

SELECT COUNT(*) AS number_of_logs
FROM event_logs
WHERE computer_name = 'computer1';

SELECT e.computer_name, e.event_type, el.level_name
FROM event_logs e
JOIN event_levels el ON e.event_level = el.level_id;

SELECT DISTINCT c.computer_name
FROM computers c
JOIN event_logs e ON c.computer_name = e.computer_name;

SELECT DISTINCT timestamp
FROM event_logs
WHERE date(event_datetime) = '2012-03-14';

SELECT event_id, computer_name
FROM event_logs
WHERE computer_name = 'Computer1';

SELECT event_logs.event_id, parsers.parser_name
FROM event_logs
JOIN parsers ON event_logs.parser = parsers.parser_id;

SELECT DISTINCT computer_name, event_level, event_datetime
FROM event_logs
WHERE data_type = 'windows:evtx:record' AND event_level > 5;

SELECT event_logs.event_id, computers.computer_name
FROM event_logs
INNER JOIN computers ON event_logs.computer_name = computers.computer_name;

SELECT DISTINCT computer_name
FROM event_logs
WHERE event_level = 5;

external_knowledge:
; The term 'particular user' refers to the username 'specific_username';
; The phrase 'within a given year' refers to the year 2022;
; 'Informational or higher in level' refers to logs with an event level of 3 or greater;
; 'A specific computer' refers to the computer with name 'specific_computer_name'.

"Past year" refers to the events that took place in 2023;
"person with the username 'john_doe'" refers to the user identified by the username 'john_doe';
"actions" refer to any activity performed by the user logged in the database, such as viewing or downloading files.

